import React, { useState } from 'react';

function Generator() {
  const [prompt, setPrompt] = useState('');
  const [generatedCode, setGeneratedCode] = useState('');
  const handleSubmit = (e) => {
    e.preventDefault();
    setGeneratedCode(`// Code generated for prompt: "${prompt}"
console.log('Hello, world!');`);
  };
  return (
    <div style={{ padding: '2rem' }}>
      <h2>AI Code Generator</h2>
      <form onSubmit={handleSubmit} style={{ marginBottom: '1rem' }}>
        <input
          type="text"
          value={prompt}
          onChange={e => setPrompt(e.target.value)}
          placeholder="Describe your project..."
          style={{ width: '300px', padding: '0.5rem' }}
        />
        <button type="submit" style={{ marginLeft: '1rem', padding: '0.5rem 1rem' }}>
          Generate Code
        </button>
      </form>
      {generatedCode && (
        <div style={{ textAlign: 'left', background: '#222', padding: '1rem', borderRadius: '8px', maxWidth: '600px', margin: '0 auto' }}>
          <pre style={{ color: '#61dafb', whiteSpace: 'pre-wrap' }}>{generatedCode}</pre>
        </div>
      )}
    </div>
  );
}

export default Generator;
